235	    fun toggleReaction(emoji: String) {
236	        if (_uiState.value.isReacting) return
237	
238	        val existingGroup = _uiState.value.reactionGroups.find { it.emoji == emoji }
239	        val viewerHasReacted = existingGroup?.viewerHasReacted == true
240	
