246	            } else {
247	                repository.addReactionToPost(postId, emoji)
248	            }
249	
250	            result
251	                .onSuccess {
252	                    // Optimistically update local state
253	                    _uiState.update { state ->
254	                        val updatedGroups = if (viewerHasReacted) {
255	                            state.reactionGroups.map { group ->
