@Composable
private fun ReactorsSheet(
    reactionGroups: List<ReactionGroup>,
    onProfileClick: (String) -> Unit,
    onClose: () -> Unit
) {
    val colors = LocalAppColors.current
    val typography = LocalAppTypography.current

    Column(
        modifier = Modifier
            .fillMaxWidth()
            .padding(16.dp)
    ) {
        Text(
            text = stringResource(R.string.reactions),
            style = typography.bodyLargeSemiBold,
            color = colors.textPrimary,
            modifier = Modifier.padding(bottom = 16.dp)
        )

        if (reactionGroups.isEmpty()) {
            Text(
                text = "No reactions yet",
                style = typography.bodyMedium,
                color = colors.textSecondary,
                modifier = Modifier.padding(vertical = 24.dp)
            )
        } else {
            reactionGroups.forEach { group ->
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    modifier = Modifier.padding(bottom = 12.dp)
                ) {
                    if (group.emoji != null) {
                        Text(text = group.emoji, style = typography.titleMedium)
                    } else if (group.customEmoji != null) {
                        AsyncImage(
                            model = group.customEmoji.imageUrl,
                            contentDescription = group.customEmoji.name,
                            modifier = Modifier.size(24.dp)
                        )
                    }
                    Spacer(modifier = Modifier.width(8.dp))
                    Text(
                        text = group.count.toString(),
                        style = typography.labelMedium,
                        color = colors.textSecondary
                    )
                }

                group.reactors.forEach { actor ->
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        modifier = Modifier
                            .fillMaxWidth()
                            .clickable { onProfileClick(actor.handle) }
                            .padding(start = 32.dp, bottom = 8.dp, top = 4.dp)
                    ) {
                        AsyncImage(
                            model = actor.avatarUrl,
                            contentDescription = null,
                            modifier = Modifier
                                .size(36.dp)
                                .clip(CircleShape),
                            contentScale = ContentScale.Crop
                        )
                        Spacer(modifier = Modifier.width(12.dp))
                        Column {
                            pub.hackers.android.ui.components.RichDisplayName(
                                name = actor.name,
                                fallback = actor.handle,
                                style = typography.bodyMedium.copy(fontWeight = FontWeight.SemiBold),
                                color = colors.textPrimary
                            )
                            Text(
                                text = actor.handle,
                                style = typography.labelMedium,
                                color = colors.textSecondary
                            )
                        }
                    }
                }

                if (group != reactionGroups.last()) {
                    HorizontalDivider(
                        color = colors.divider,
                        modifier = Modifier.padding(vertical = 8.dp)
                    )
                }
            }
        }
    }
}

